def get_score(dice):
    from collections import Counter

    # Count occurrences of each die value
    counts = Counter(dice)
    score = 0

    # Check for Straight
    if len(dice) == 6 and all(counts[i] > 0 for i in range(1, 7)):
        return 1000

    # Check for Three Pairs
    pairs = sum(1 for count in counts.values() if count == 2)
    if pairs == 3:
        return 750

    # Check for Three, Four, Five, and Six of a Kind
    for num in range(1, 7):
        if counts[num] >= 3:
            if num == 1:
                score += 1000 * (counts[num] // 3)
            else:
                score += 100 * num * (counts[num] // 3)
            counts[num] -= 3 * (counts[num] // 3)  # Remove used dice

        # Check for Four, Five, and Six of a Kind
        if counts[num] == 4:
            score += 2 * (1000 if num == 1 else 100 * num)
        elif counts[num] == 5:
            score += 3 * (1000 if num == 1 else 100 * num)
        elif counts[num] == 6:
            score += 4 * (1000 if num == 1 else 100 * num)

    # Check for Individual 1s and 5s
    score += 100 * counts[1]
    score += 50 * counts[5]

    # Return Result
    if score == 0:
        return "Zonk"
    return score

