def format_number(n):
    if n == 0:
        return ""

    num_str = str(n)
    length = len(num_str)
    parts = []

    for i, digit in enumerate(num_str):
        if digit != '0':
            power = length - i - 1
            if power > 0:
                parts.append(f"{digit}*{10**power}")
            else:
                parts.append(f"{digit}")

    return "+".join(parts)

