        return False

    map1 = {}
    map2 = {}

    for c1, c2 in zip(string1, string2):
        # Check if c1 is already mapped to a different character
        if c1 in map1:
            if map1[c1] != c2:
                return False
        else:
            map1[c1] = c2

        # Check if c2 is already mapped to a different character
        if c2 in map2:
