def hofstadter_q(n, memo=None):
    if memo is None:
        memo = {}
    if n in memo:
        return memo[n]
    if n == 1 or n == 2:
        return 1
    # Calculate the result using the recursive formula
    result = hofstadter_q(n - hofstadter_q(n - 1, memo), memo) + hofstadter_q(n - hofstadter_q(n - 2, memo), memo)
    # Store the result in the memoization dictionary
    memo[n] = result
    return result

