def alphabet_war(fight: str) -> str:
    left_side = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    right_side = {'m': 4, 'q': 3, 'd': 2, 'z': 1}

    left_power = 0
    right_power = 0
    neutralized_indices = set()

    # Identify neutralized indices due to bombs
    for i, char in enumerate(fight):
        if char == '*':
            neutralized_indices.add(i)
            if i > 0:
                neutralized_indices.add(i - 1)
            if i < len(fight) - 1:
                neutralized_indices.add(i + 1)

    # Calculate power for each side
    for i, char in enumerate(fight):
        if i not in neutralized_indices:
            if char in left_side:
                left_power += left_side[char]
            elif char in right_side:
                right_power += right_side[char]

    # Determine the winner
    if left_power > right_power:
        return "Left side wins!"
    elif right_power > left_power:
        return "Right side wins!"
    else:
        return "Let's fight again!"

