def battle(player1, player2):
    # Initialize lists to store surviving creatures
    survivors1 = []
    survivors2 = []

    # Function to validate a creature
    def is_valid_creature(creature):
        if not isinstance(creature, list) or len(creature) != 2:
            return False
        power, toughness = creature
        return isinstance(power, int) and isinstance(toughness, int) and power >= 0 and toughness > 0

    # Iterate over both players' creatures simultaneously
    # The zip function will stop at the shortest list, leaving extra creatures unblocked
    for creature1, creature2 in zip(player1, player2):
        # Validate creatures
        if not is_valid_creature(creature1) or not is_valid_creature(creature2):
            raise ValueError("Invalid creature detected. Creatures must be lists of two non-negative integers.")

        power1, toughness1 = creature1
        power2, toughness2 = creature2

        # Determine if each creature survives the battle
        if power2 < toughness1:
            survivors1.append(creature1)
        if power1 < toughness2:
            survivors2.append(creature2)

    # Handle unblocked creatures
    # Any remaining creatures in the longer list are considered unblocked and automatically survive
    for creature in player1[len(player2):]:
        if is_valid_creature(creature):
            survivors1.append(creature)
        else:
            raise ValueError("Invalid creature detected. Creatures must be lists of two non-negative integers.")
    for creature in player2[len(player1):]:
        if is_valid_creature(creature):
            survivors2.append(creature)
        else:
            raise ValueError("Invalid creature detected. Creatures must be lists of two non-negative integers.")

    # Return the result as a dictionary
    return {
        "player1": survivors1,
        "player2": survivors2
    }

