def getAllPrimeFactors(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]

    factors = []
    # Check for number of 2s
    while n % 2 == 0:
        factors.append(2)
        n //= 2

    # Check for odd factors
    divisor = 3
    while divisor * divisor <= n:
        while n % divisor == 0:
            factors.append(divisor)
            n //= divisor
        divisor += 2

    # If n is a prime number greater than 2
    if n > 2:
        factors.append(n)

    return factors

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, int) or n <= 0:
        return [[], []]
    if n == 1:
        return [[1], [1]]

    factors = getAllPrimeFactors(n)
    unique_factors = []
    counts = []

    for factor in factors:
        if factor in unique_factors:
            counts[unique_factors.index(factor)] += 1
        else:
            unique_factors.append(factor)
            counts.append(1)

    return [unique_factors, counts]

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]

    unique_factors, counts = getUniquePrimeFactorsWithCount(n)
    products = [factor ** count for factor, count in zip(unique_factors, counts)]

    return products

def find_greatest_difference(couples):
    # Check if the input list is empty
    if not couples or couples == ['']:
        return False

    max_difference = -1
    result_couple = None

    for couple in couples:
        # Validate the format of the couple
        parts = couple.split('-')
        if len(parts) != 2:
            continue  # Skip invalid format

        try:
            num1, num2 = map(int, parts)
        except ValueError:
            continue  # Skip if conversion to integer fails

        difference = abs(num1 - num2)

        if difference > max_difference:
            max_difference = difference
            result_couple = couple

    # If no valid couple with a difference was found, return False
    if max_difference == -1:
        return False
    else:
        return result_couple

