def transform_string(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    exceptions = {'c': -1, 'o': -1, 'd': -3, 'e': -4}
    exception_reverts = {'c', 'o', 'd', 'e'}

    def move_forward(c, steps):
        return chr((ord(c) - ord('a') + steps) % 26 + ord('a'))

    def move_backward(c, steps):
        return chr((ord(c) - ord('a') - steps) % 26 + ord('a'))

    result = []

    for char in s:
        if char in exceptions:
            new_char = move_backward(char, -exceptions[char])
        elif char in vowels:
            new_char = move_backward(char, 5)
        else:
            new_char = move_forward(char, 9)

        if new_char in exception_reverts:
            new_char = char

        result.append(new_char)

    return ''.join(result)

