def replace_yellow_shades(color):
    # Dictionary for HTML color name replacements
    yellow_to_green = {
        "gold": "ForestGreen",
        "khaki": "LimeGreen",
        "lemonchiffon": "PaleGreen",
        "lightgoldenrodyellow": "SpringGreen",
        "lightyellow": "MintCream",
        "palegoldenrod": "LightGreen",
        "yellow": "Lime"
    }

    # Function to check if a string is a valid hex color code
    def is_valid_hex_color(s):
        if len(s) == 7 and s.startswith('#'):
            try:
                int(s[1:], 16)
                return True
            except ValueError:
                return False
        return False

    # Check if the input is a hex color code
    if is_valid_hex_color(color):
        # Extract RGB components
        r = int(color[1:3], 16)
        g = int(color[3:5], 16)
        b = int(color[5:7], 16)

        # Check if the color is "yellow"
        if r > b and g > b:
            # Rearrange the components
            rgb = sorted([(r, 'r'), (g, 'g'), (b, 'b')], reverse=True)
            new_r = rgb[2][0]
            new_g = rgb[0][0]
            new_b = rgb[1][0]

            # Convert back to hex
            new_color = f"#{new_r:02X}{new_g:02X}{new_b:02X}"

            # Maintain the original case
            if color.islower():
                return new_color.lower()
            else:
                return new_color.upper()
        else:
            return color
    else:
        # Process HTML color names
        color_lower = color.lower()
        if color_lower in yellow_to_green:
            return yellow_to_green[color_lower]
        else:
            # Return the original color name if not a yellow shade
            return color

