def can_be_increasing(sequence):
    def is_strictly_increasing(seq):
        return all(seq[i] < seq[i + 1] for i in range(len(seq) - 1))

    # Count the number of violations
    violations = 0
    for i in range(len(sequence) - 1):
        if sequence[i] >= sequence[i + 1]:
            violations += 1
            if violations > 1:
                return False
            # Check if removing sequence[i] or sequence[i+1] can fix the sequence
            if i > 0 and sequence[i - 1] >= sequence[i + 1] and i + 2 < len(sequence) and sequence[i] >= sequence[i + 2]:
                return False

    return True

