    total_product = 1
    zero_count = 0
    negative_count = 0
    min_negative = float('inf')
    max_negative = float('-inf')

    for num in arr:
        if num != 0:
            total_product *= num
            if num < 0:
                negative_count += 1
                min_negative = min(min_negative, num)
                max_negative = max(max_negative, num)
        else:
            zero_count += 1

    max_product = float('-inf')
    element_to_remove = None

    for num in arr:
        if num == 0:
            if zero_count > 1:
                current_product = 0
            else:
                current_product = total_product
        else:
            if zero_count > 0:
                current_product = 0
            else:
                current_product = total_product // num

        if current_product > max_product:
            max_product = current_product
            element_to_remove = num
        elif current_product == max_product:
