def solve(s):
    vowels = "aeiou"
    vowel_list = []
    consonant_list = []

    # Separate characters into vowels and consonants
    for char in s:
        if char in vowels:
            vowel_list.append(char)
        else:
            consonant_list.append(char)

    # Count vowels and consonants
    num_vowels = len(vowel_list)
    num_consonants = len(consonant_list)

    # If the difference in count is greater than 1, or if all are vowels or all are consonants, return "failed"
    if abs(num_vowels - num_consonants) > 1 or num_vowels == 0 or num_consonants == 0:
        return "failed"

    # Sort both lists
    vowel_list.sort()
    consonant_list.sort()

    # Determine starting character
    result = []
    if num_vowels > num_consonants:
        start_with_vowel = True
    elif num_consonants > num_vowels:
        start_with_vowel = False
    else:
        start_with_vowel = True  # If equal, start with a vowel

    # Construct the result by alternating
    v_index, c_index = 0, 0
    while v_index < num_vowels or c_index < num_consonants:
        if start_with_vowel:
            if v_index < num_vowels:
                result.append(vowel_list[v_index])
                v_index += 1
            start_with_vowel = False
        else:
            if c_index < num_consonants:
                result.append(consonant_list[c_index])
                c_index += 1
            start_with_vowel = True

    return ''.join(result)

