def find_age_difference(ages):
    # Filter out negative ages and non-integer inputs
    valid_ages = []
    for age in ages:
        try:
            age = int(age)  # Attempt to convert to integer
            if age >= 0:
                valid_ages.append(age)
        except ValueError:
            continue  # Ignore non-integer values

    # Check if the list of valid ages is empty
    if not valid_ages:
        return (None, None, None)

    # Initialize variables
    youngest_age = float('inf')
    oldest_age = float('-inf')

    # Loop through valid ages
    for age in valid_ages:
        if age < youngest_age:
            youngest_age = age
        if age > oldest_age:
            oldest_age = age

    # Calculate difference
    age_difference = oldest_age - youngest_age

    # Return result
    return (youngest_age, oldest_age, age_difference)

