def sum_of_divisors(n):
    total = 0
    sqrt_n = int(n**0.5)

    for i in range(1, sqrt_n + 1):
        total += n // i
        if i != n // i:
            total += (n // i - n // (i + 1)) * i

    # Correct the logic to ensure each divisor pair is counted once
    for i in range(1, sqrt_n + 1):
        total += (n // i - n // (i + 1)) * i

    return total

