def words_to_number(s):
    # Ensure the input is a string
    if not isinstance(s, str):
        raise ValueError("Input must be a string")

    # Convert input to string to avoid issues with non-string input
    s = str(s)

    # Define word mappings
    units = {
        "zero": 0, "one": 1, "two": 2, "three": 3, "four": 4,
        "five": 5, "six": 6, "seven": 7, "eight": 8, "nine": 9
    }
    teens = {
        "eleven": 11, "twelve": 12, "thirteen": 13, "fourteen": 14,
        "fifteen": 15, "sixteen": 16, "seventeen": 17, "eighteen": 18, "nineteen": 19
    }
    tens = {
        "ten": 10, "twenty": 20, "thirty": 30, "forty": 40,
        "fifty": 50, "sixty": 60, "seventy": 70, "eighty": 80, "ninety": 90
    }
    large_numbers = {
        "hundred": 100, "thousand": 1000, "million": 1000000
    }

    # Preprocess input
    s = s.replace(" and ", " ")
    words = s.split()

    # Initialize variables
    current_number = 0
    total_sum = 0

    # Iterate over words
    for word in words:
        # Handle compound words like "twenty-four"
        subwords = word.split('-')
        for subword in subwords:
            if subword in units:
                current_number += units[subword]
            elif subword in teens:
                current_number += teens[subword]
            elif subword in tens:
                current_number += tens[subword]
            elif subword == "hundred":
                current_number *= large_numbers[subword]

        if word in large_numbers and word != "hundred":
            current_number *= large_numbers[word]
            total_sum += current_number
            current_number = 0

    # Finalize the result
    total_sum += current_number

    # Return the result
