def count_product_ways(n, k):
    memo = {}

    def helper(n, k, min_factor):
        if k == 1:
            return 1
        if (n, k, min_factor) in memo:
            return memo[(n, k, min_factor)]

        count = 0
        for i in range(min_factor, int(n**0.5) + 1):
            if n % i == 0:
                count += helper(n // i, k - 1, i)

        # Consider the case where the factor is greater than sqrt(n)
        if min_factor <= n:
            count += helper(1, k - 1, n)

        memo[(n, k, min_factor)] = count
        return count

    return helper(n, k, 1)

