def gcd(a, b):
    # Calculate the greatest common divisor using the Euclidean algorithm
    while b:
        a, b = b, a % b
    return a

def prime_factors(n):
    # Find all prime factors of n
    i = 2
    factors = set()
    while i * i <= n:
        while (n % i) == 0:
            factors.add(i)
            n //= i
        i += 1
    if n > 1:
        factors.add(n)
    return factors

def euler_totient(d):
    # Calculate Euler's Totient function φ(d)
    if d == 1:
        return 0
    result = d
    for p in prime_factors(d):
        result *= (p - 1)
        result //= p
    return result

def proper_fractions(d):
    # Return the number of reduced proper fractions with denominator d
    return euler_totient(d)

