def mix(s1, s2):
    from collections import defaultdict

    # Initialize frequency counters
    freq_s1 = defaultdict(int)
    freq_s2 = defaultdict(int)

    # Count frequencies in s1
    for char in s1:
        if char.islower():
            freq_s1[char] += 1

    # Count frequencies in s2
    for char in s2:
        if char.islower():
            freq_s2[char] += 1

    # Determine maximum frequencies
    max_freq = {}
    for char in set(freq_s1.keys()).union(set(freq_s2.keys())):
        count1 = freq_s1.get(char, 0)
        count2 = freq_s2.get(char, 0)
        if count1 > 1 or count2 > 1:
            if count1 > count2:
                max_freq[char] = (count1, '1')
            elif count2 > count1:
                max_freq[char] = (count2, '2')
            else:
                max_freq[char] = (count1, '=')

    # Filter and format results
    formatted_substrings = []
    for char, (count, source) in max_freq.items():
        formatted_substrings.append(f"{source}:{char * count}")

    # Sort and construct final string
    formatted_substrings.sort(key=lambda x: (-len(x), x))
    result = '/'.join(formatted_substrings)

    # Return the result
    return result

