import re

def differentiate(polynomial, x_value):
    # Parse the polynomial into terms
    terms = re.findall(r'([+-]?\d*)x(?:\^(\d+))?|([+-]?\d+)', polynomial)

    derivative_terms = []

    for coeff, exp, constant in terms:
        if constant:
            # This is a constant term, derivative is 0
            continue

        # Handle coefficient
        if coeff == '' or coeff == '+':
            coeff = 1
        elif coeff == '-':
            coeff = -1
        else:
            coeff = int(coeff)

        # Handle exponent
        if exp == '' or exp is None:
            exp = 1
        else:
            exp = int(exp)

        # Apply power rule: d/dx [ax^n] = n*ax^(n-1)
        if exp > 0:
            new_coeff = coeff * exp
            new_exp = exp - 1
            derivative_terms.append((new_coeff, new_exp))

    # Evaluate the derivative at x_value
    result = 0
    for coeff, exp in derivative_terms:
        result += coeff * (x_value ** exp)

    return result

