def make_valid_tree(n, a):
    # Initialize data structures
    parent_count = [0] * (n + 1)
    root_candidates = []

    # Count the number of times each index is referenced as a parent
    for i in range(n):
        parent_count[a[i]] += 1

    # Identify the root candidates
    for i in range(1, n + 1):
        if parent_count[i] == 0:
            root_candidates.append(i)

    # Correct the sequence
    changes = 0
    root = None

    for i in range(n):
        if a[i] == i + 1:
            if root is None:
                root = i + 1
            else:
                # If we already have a root, change this to a candidate
                if root_candidates:
                    a[i] = root_candidates.pop()
                    changes += 1
        elif parent_count[a[i]] > 1:
            parent_count[a[i]] -= 1
            if root_candidates:
                a[i] = root_candidates.pop()
                parent_count[a[i]] += 1
                changes += 1

    # Ensure there's exactly one root
    if root is None:
        if root_candidates:
            root = root_candidates.pop()
            for i in range(n):
                if a[i] == root:
                    break
            else:
                a[0] = root
                changes += 1

    return changes, a

