def balance_boxes():
    import sys
    input = sys.stdin.read
    data = input().splitlines()

    k = int(data[0])
    boxes = []
    total_sum = 0

    for i in range(1, k + 1):
        line = list(map(int, data[i].split()))
        n_i = line[0]
        numbers = line[1:]
        boxes.append(numbers)
        total_sum += sum(numbers)

    if total_sum % k != 0:
        print("No")
        return

    target_sum = total_sum // k
    current_sums = [sum(box) for box in boxes]

    # To store the redistribution plan
    redistribution_plan = [-1] * k

    # Create a map from number to its box and index
    number_to_box = {}
    for i in range(k):
        for j, num in enumerate(boxes[i]):
            number_to_box[num] = (i, j)

    # Try to find a cycle of moves that balances the boxes
    def find_cycle(start_box, visited, path):
        if start_box in visited:
            return visited[start_box] == 0

        visited[start_box] = 0
        path.append(start_box)

        for idx, num in enumerate(boxes[start_box]):
            # Calculate the needed number to balance the current box
            needed = target_sum - (current_sums[start_box] - num)
            if needed in number_to_box:
                next_box, _ = number_to_box[needed]
                if next_box != start_box:
                    redistribution_plan[start_box] = (num, next_box + 1)
                    if find_cycle(next_box, visited, path):
                        return True

        visited[start_box] = 1
        path.pop()
        return False

    for start_box in range(k):
        visited = {}
        path = []
        if find_cycle(start_box, visited, path):
            break

    if -1 in redistribution_plan:
        print("No")
    else:
        print("Yes")
        for num, target in redistribution_plan:
            print(num, target)

