def min_time_to_feed_rabbits(n, k, carrot_lengths):
    def can_divide_with_max_length(max_length):
        total_pieces = 0
        for length in carrot_lengths:
            total_pieces += (length + max_length - 1) // max_length
        return total_pieces <= k

    low, high = 1, max(carrot_lengths)

    while low < high:
        mid = (low + high) // 2
        if can_divide_with_max_length(mid):
            high = mid
        else:
            low = mid + 1

    optimal_max_length = low
    total_time = 0

    for length in carrot_lengths:
        full_pieces = length // optimal_max_length
        remainder = length % optimal_max_length
        total_time += full_pieces * (optimal_max_length ** 2)
        if remainder > 0:
            total_time += remainder ** 2

    return total_time

